$pageTitle='Account Billing';$pageDescription='Manage Stonefellow membership billing.';$pageClass='membership-page billing-page';require __DIR__.'/includes/membership_tiers.php';require_once __DIR__.'/includes/billing_cancellation.php';$user=sf_require_login();if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){if(!sf_verify_csrf($_POST['csrf_token']??null))sf_auth_flash('error','Security check failed.');elseif(($_POST['action']??'')==='cancel_subscription')sf_billing_cancel_subscription_secure((int)($_POST['subscription_id']??0),false);elseif(($_POST['action']??'')==='cancel_now')sf_billing_cancel_subscription_secure((int)($_POST['subscription_id']??0),true);sf_redirect(sf_url('account-billing.php'));}$subscription=sf_billing_active_subscription((int)$user['id']);$invoices=sf_billing_user_invoices((int)$user['id']);$transactions=sf_billing_user_transactions((int)$user['id']);require __DIR__.'/includes/header.php';
?>
<section class="sf-billing-hero"><span class="sf-kicker">Account Billing</span><h1>Membership, invoices, and payments.</h1><p>Subscription changes are recorded locally only after provider confirmation.</p></section><section class="sf-billing-layout"><article class="sf-billing-card"><div class="sf-billing-card-head"><span>Current Subscription</span><strong><?= $subscription?sf_auth_h($subscription['status']):'Free' ?></strong></div><?php if($subscription): ?><h2><?= sf_auth_h($subscription['plan_name']??'Stonefellow Membership') ?></h2><div class="sf-billing-price"><?= sf_billing_money((int)($subscription['price_cents']??0)) ?><span>/ <?= sf_auth_h($subscription['billing_interval']??'month') ?></span></div><p>Period ends: <strong><?= sf_auth_h($subscription['current_period_end']??'Not set') ?></strong></p><?php if(!empty($subscription['cancel_at_period_end'])): ?><div class="sf-payment-sandbox-box"><strong>Cancellation scheduled</strong></div><?php elseif(in_array(($subscription['status']??''),['active','trialing','past_due'],true)): ?><form method="post" class="sf-billing-actions sf-danger-actions"><?= sf_csrf_field() ?><input type="hidden" name="subscription_id" value="<?= (int)$subscription['id'] ?>"><button class="sf-secondary-action" name="action" value="cancel_subscription">Cancel at Period End</button><button class="sf-danger-action" name="action" value="cancel_now">Cancel Now</button></form><?php endif; ?><?php else: ?><h2>No active membership</h2><a class="sf-primary-action" href="<?= sf_url('subscribe.php') ?>">Choose Plan</a><?php endif; ?></article><aside class="sf-billing-card"><span class="sf-panel-eyebrow">Provider Integrity</span><h2>Fail-closed cancellation</h2><p>If the payment provider does not confirm the request, local access remains unchanged.</p></aside></section><section class="sf-admin-panel"><h2>Invoices</h2><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Invoice</th><th>Status</th><th>Total</th><th>Created</th></tr></thead><tbody><?php foreach($invoices as$i): ?><tr><td><?= sf_auth_h($i['invoice_number']??'') ?></td><td><?= sf_auth_h($i['status']??'') ?></td><td><?= sf_billing_money((int)($i['total_cents']??0),(string)($i['currency']??'USD')) ?></td><td><?= sf_auth_h($i['created_at']??'') ?></td></tr><?php endforeach; ?></tbody></table></div></section><section class="sf-admin-panel"><h2>Transactions</h2><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Provider</th><th>Status</th><th>Amount</th><th>Created</th></tr></thead><tbody><?php foreach($transactions as$t): ?><tr><td><?= sf_auth_h($t['provider']??'') ?></td><td><?= sf_auth_h($t['status']??'') ?></td><td><?= sf_billing_money((int)($t['amount_cents']??0),(string)($t['currency']??'USD')) ?></td><td><?= sf_auth_h($t['created_at']??'') ?></td></tr><?php endforeach; ?></tbody></table></div></section>
